codeSnippetEN:
abstract class Converter {
  abstract int convert(int x);
  void show(int x) {
    System.out.println(convert(x));
  }
}
class Doubler extends Converter {
  int convert(int x) { return x * 2; }
}

new Doubler().show(5);

codeSnippetPL:
abstract class Konwerter {
  abstract int konwertuj(int x);
  void pokaz(int x) {
    System.out.println(konwertuj(x));
  }
}
class Podwajacz extends Konwerter {
  int konwertuj(int x) { return x * 2; }
}

new Podwajacz().pokaz(5);

